module RefModule(
    input [7:0] A,
    input [7:0] B,
    input SEL,
    output reg [7:0] OUT
);wire [7:0] negB;
      wire _n01 = (~B)[0] ^ 1[0];
  wire _c01 = (~B)[0] & 1[0];
  wire _n02 = (~B)[1] ^ 1[1] ^ _c01;
  wire _c02 = ((~B)[1] & 1[1]) | ((~B)[1] & _c01) | (1[1] & _c01);
  wire _n03 = (~B)[2] ^ 1[2] ^ _c02;
  wire _c03 = ((~B)[2] & 1[2]) | ((~B)[2] & _c02) | (1[2] & _c02);
  wire _n04 = (~B)[3] ^ 1[3] ^ _c03;
  wire _c04 = ((~B)[3] & 1[3]) | ((~B)[3] & _c03) | (1[3] & _c03);
  assign negB = {_n01, _n02, _n03, _n04};

    always @(*) begin
        if (SEL == 0) begin
            OUT = A + B;
        end else begin
            OUT = A + negB;
        end
    end

endmodule
